#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define MAX_POINTS 75000

typedef struct Point {
    int x, y;
} Point;

int comparePoints(const void *a, const void *b) {
    Point *p1 = (Point *)a;
    Point *p2 = (Point *)b;
    if (p1->x < p2->x) return -1;
    if (p1->x > p2->x) return 1;
    if (p1->y < p2->y) return -1;
    if (p1->y > p2->y) return 1;
    return 0;
}

int calculateDistance(Point *p1, Point *p2) {
    return (p1->x - p2->x) * (p1->x - p2->x) + (p1->y - p2->y) * (p1->y - p2->y);
}

int main() {
    int Q;
    scanf("%d", &Q);
    Point points[MAX_POINTS];
    int numPoints = 0;
    for (int i = 0; i < Q; i++) {
        char query;
        int x, y;
        scanf(" %c %d %d", &query, &x, &y);
        if (query == '+') {
            points[numPoints].x = x;
            points[numPoints].y = y;
            numPoints++;
        } else {
            for (int j = 0; j < numPoints; j++) {
                if (points[j].x == x && points[j].y == y) {
                    for (int k = j; k < numPoints - 1; k++) {
                        points[k] = points[k + 1];
                    }
                    numPoints--;
                    break;
                }
            }
        }
        int minDistance = 0;
        if (numPoints >= 2) {
            minDistance = calculateDistance(&points[0], &points[1]);
            for (int j = 0; j < numPoints; j++) {
                for (int k = j + 1; k < numPoints; k++) {
                    int distance = calculateDistance(&points[j], &points[k]);
                    if (distance < minDistance) {
                        minDistance = distance;
                    }
                }
            }
        }
        printf("%d\n", minDistance);
    }
    return 0;
}

