#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>
using namespace std;

struct Point {
    int x, y;
};

int calculateDistance(const Point &p1, const Point &p2) {
    return (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y);
}

int main() {
    int Q;
    cin >> Q;
    vector<Point> points;
    for (int i = 0; i < Q; i++) {
        char query;
        int x, y;
        cin >> query >> x >> y;
        if (query == '+') {
            points.push_back({x, y});
        } else {
            for (auto it = points.begin(); it != points.end(); it++) {
                if (it->x == x && it->y == y) {
                    points.erase(it);
                    break;
                }
            }
        }
        int minDistance = 0;
        if (points.size() >= 2) {
            minDistance = calculateDistance(points[0], points[1]);
            for (int j = 0; j < points.size(); j++) {
                for (int k = j + 1; k < points.size(); k++) {
                    int distance = calculateDistance(points[j], points[k]);
                    if (distance < minDistance) {
                        minDistance = distance;
                    }
                }
            }
        }
        cout << minDistance << endl;
    }
    return 0;
}

