import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

class Point {
    int x, y;
    Point(int x, int y) {
        this.x = x;
        this.y = y;
    }
}

public class Main {
    public static int calculateDistance(Point p1, Point p2) {
        return (p1.x - p2.x) * (p1.x - p2.x) + (p1.y - p2.y) * (p1.y - p2.y);
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int Q = scanner.nextInt();
        List<Point> points = new ArrayList<>();
        for (int i = 0; i < Q; i++) {
            char query = scanner.next().charAt(0);
            int x = scanner.nextInt();
            int y = scanner.nextInt();
            if (query == '+') {
                points.add(new Point(x, y));
            } else {
                for (int j = 0; j < points.size(); j++) {
                    if (points.get(j).x == x && points.get(j).y == y) {
                        points.remove(j);
                        break;
                    }
                }
            }
            int minDistance = 0;
            if (points.size() >= 2) {
                minDistance = calculateDistance(points.get(0), points.get(1));
                for (int j = 0; j < points.size(); j++) {
                    for (int k = j + 1; k < points.size(); k++) {
                        int distance = calculateDistance(points.get(j), points.get(k));
                        if (distance < minDistance) {
                            minDistance = distance;
                        }
                    }
                }
            }
            System.out.println(minDistance);
        }
    }
}

